use std::cmp::min;

struct TarjanContext {
    timer: usize,
    scc_cnt: usize,
    dfn: Vec<usize>,
    low: Vec<usize>,
    scc_id: Vec<usize>,
    in_stack: Vec<bool>,
    stack: Vec<usize>,
}

impl TarjanContext {
    fn new(n: usize) -> Self {
        TarjanContext {
            timer: 0,
            scc_cnt: 0,
            dfn: vec![0; n],
            low: vec![0; n],
            scc_id: vec![0; n],
            in_stack: vec![false; n],
            stack: Vec::new(),
        }
    }
}

fn tarjan(u: usize, adj: &Vec<Vec<usize>>, ctx: &mut TarjanContext) {
    ctx.timer += 1;
    ctx.dfn[u] = ctx.timer;
    ctx.low[u] = ctx.timer;
    ctx.stack.push(u);
    ctx.in_stack[u] = true;

    for &v in &adj[u] {
        if ctx.dfn[v] == 0 {
            tarjan(v, adj, ctx);
            ctx.low[u] = min(ctx.low[u], ctx.low[v]);
        } else if ctx.in_stack[v] {
            ctx.low[u] = min(ctx.low[u], ctx.dfn[v]);
        }
    }

    if ctx.low[u] == ctx.dfn[u] {
        ctx.scc_cnt += 1;
        loop {
            let v = ctx.stack.pop().unwrap();
            ctx.in_stack[v] = false;
            ctx.scc_id[v] = ctx.scc_cnt;
            if u == v {
                break;
            }
        }
    }
}

